// Build the per-platform schedule array. Each item becomes one Posta
// create-and-schedule run via Split In Batches.
//
// EDIT BELOW: your three social account IDs + peak-hour offsets per platform.
const accounts = {
  linkedin: 'REPLACE_LINKEDIN_ACCOUNT_ID',   // e.g. '35'
  bluesky:  'REPLACE_BLUESKY_ACCOUNT_ID',    // e.g. '16'
  threads:  'REPLACE_THREADS_ACCOUNT_ID',    // e.g. '42'
};
// 24h clock, UTC. LinkedIn ~09 UTC, Bluesky ~12, Threads ~18 are sane defaults.
const peakHours = { linkedin: 9, bluesky: 12, threads: 18 };

// Parse the JSON from Claude (strip markdown fences if any slipped through).
const raw = $input.first().json.content[0].text || '';
const stripped = raw.replace(/^```(?:json)?\s*|\s*```$/g, '').trim();
const captions = JSON.parse(stripped);

const today = new Date();
function at(hour) {
  const d = new Date(today);
  d.setUTCHours(hour, 0, 0, 0);
  return d.toISOString();
}

return Object.keys(captions).map((platform) => ({
  json: {
    platform,
    caption: captions[platform],
    socialAccountIds: [accounts[platform]],
    scheduledAt: at(peakHours[platform]),
  },
}));
